}

\definepiece{wK}{%
  \fontfamily{cmr}\selectfont
  \textcolor{white}{K}
}
\definepiece{wQ}{%
  \fontfamily{cmr}\selectfont
  \textcolor{white}{Q}
}
\definepiece{wR}{%
  \fontfamily{cmr}\selectfont
